import{_ as t,o as a,c as i,a2 as n}from"./chunks/framework.BWuWLRhz.js";const g=JSON.parse('{"title":"Integrations & Webhooks","description":"","frontmatter":{},"headers":[],"relativePath":"app/integrations.md","filePath":"app/integrations.md"}'),o={name:"app/integrations.md"};function s(r,e,d,h,p,l){return a(),i("div",null,[...e[0]||(e[0]=[n(`<h1 id="integrations-webhooks" tabindex="-1">Integrations &amp; Webhooks <a class="header-anchor" href="#integrations-webhooks" aria-label="Permalink to &quot;Integrations &amp; Webhooks&quot;">​</a></h1><p>Integrations connect your Git hosting provider (forge) to Tragwerk so that a <code>git push</code> automatically triggers a build and deployment. Each project has its own webhook integration with a unique signing secret.</p><h2 id="creating-a-webhook-integration" tabindex="-1">Creating a webhook integration <a class="header-anchor" href="#creating-a-webhook-integration" aria-label="Permalink to &quot;Creating a webhook integration&quot;">​</a></h2><p>Open <strong>Integrations</strong> for the active project and choose <strong>Create integration</strong>. You select the Git forge that hosts the repository; Tragwerk generates a random signing secret and exposes a forge-specific receiver endpoint.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Only <strong>one</strong> webhook integration may exist per project at a time. Delete the existing integration before creating a new one for a different forge.</p></div><p>Supported forges:</p><table tabindex="0"><thead><tr><th>Forge</th><th>Route slug</th></tr></thead><tbody><tr><td>GitHub</td><td><code>github</code></td></tr><tr><td>GitLab</td><td><code>gitlab</code></td></tr><tr><td>Forgejo</td><td><code>forgejo</code></td></tr><tr><td>Gitea</td><td><code>gitea</code></td></tr><tr><td>Codeberg</td><td><code>codeberg</code></td></tr><tr><td>Bitbucket</td><td><code>bitbucket</code></td></tr></tbody></table><p>After creating the integration, copy the endpoint URL and secret into your forge&#39;s webhook settings (push events only).</p><h3 id="forge-endpoint" tabindex="-1">Forge endpoint <a class="header-anchor" href="#forge-endpoint" aria-label="Permalink to &quot;Forge endpoint&quot;">​</a></h3><p>Each integration is served at:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>POST /webhooks/{forge}/{projectId}</span></span></code></pre></div><p>For example, a GitHub integration for project <code>abc123</code> is reached at <code>https://your-tragwerk-host/webhooks/github/abc123</code>. The handler:</p><ol><li>Resolves the forge from the route slug and loads the project.</li><li>Looks up the project&#39;s stored integration secret.</li><li>Verifies the request signature against that secret (returns <code>401</code> on mismatch).</li><li>Extracts the push payload (branch + commit SHA).</li><li>Dispatches a build for that branch, or — when the push deletes a branch — tears down the matching <a href="/app/environments">environment</a>.</li></ol><h3 id="deleting-an-integration" tabindex="-1">Deleting an integration <a class="header-anchor" href="#deleting-an-integration" aria-label="Permalink to &quot;Deleting an integration&quot;">​</a></h3><p>On the <strong>Integrations</strong> page, use <strong>Delete</strong> next to the integration. This removes the secret and disables the receiver endpoint; existing deployments are not affected.</p><h2 id="generic-git-push-receiver" tabindex="-1">Generic git-push receiver <a class="header-anchor" href="#generic-git-push-receiver" aria-label="Permalink to &quot;Generic git-push receiver&quot;">​</a></h2><p>Tragwerk also exposes a forge-agnostic receiver used internally and for custom setups:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>POST /webhooks/git-push</span></span></code></pre></div><p>It expects a JSON/form body with <code>projectId</code>, <code>branch</code>, and <code>newSha</code>. A <code>newSha</code> of all zeros (<code>0000…0000</code>) signals a deleted branch and removes the corresponding environment; any other SHA dispatches a build for that branch.</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;projectId&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;abc123&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;branch&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;main&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;newSha&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h2 id="internal-git-auth-endpoint" tabindex="-1">Internal git-auth endpoint <a class="header-anchor" href="#internal-git-auth-endpoint" aria-label="Permalink to &quot;Internal git-auth endpoint&quot;">​</a></h2><p>The server-side Git hosting integration uses an internal endpoint to authenticate Git operations between the VPS and Tragwerk:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>POST /internal/git-auth</span></span></code></pre></div><p>This endpoint is for server-to-server communication only and is not part of the end-user workflow. It does not require an authenticated user session.</p><h2 id="example-wiring-up-github" tabindex="-1">Example: wiring up GitHub <a class="header-anchor" href="#example-wiring-up-github" aria-label="Permalink to &quot;Example: wiring up GitHub&quot;">​</a></h2><ol><li>In Tragwerk, open <strong>Integrations</strong> and create a <strong>GitHub</strong> integration.</li><li>Copy the endpoint URL (<code>/webhooks/github/{projectId}</code>) and the generated secret.</li><li>In GitHub, go to <strong>Settings → Webhooks → Add webhook</strong>.</li><li>Set the <strong>Payload URL</strong> to the Tragwerk endpoint, <strong>Content type</strong> to <code>application/json</code>, paste the <strong>Secret</strong>, and select <strong>Just the push event</strong>.</li><li>Push a commit — Tragwerk verifies the signature and starts a <a href="/app/deployments">deployment</a>.</li></ol><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/app/projects">Projects</a></li><li><a href="/app/environments">Environments</a></li><li><a href="/app/deployments">Deployments</a></li></ul>`,28)])])}const u=t(o,[["render",s]]);export{g as __pageData,u as default};
